const item = $input.first();
const isWebhook = !!item?.json?.body;
const body = item?.json?.body || {};
return [{ json: {
  trigger: isWebhook ? 'webhook' : 'schedule',
  mode: body.mode || 'rss',
  source_id: body.source_id || null,
  triggered_at: new Date().toISOString()
}}];

const results = $input.first().json.results || [];
if (!results.length) return [{ json: { sources: [], count: 0 } }];

const sources = results.map(page => {
  const p = page.properties || {};
  const title = (p['Name']?.title || []).map(t => t.plain_text).join('');
  const feedUrl = p['Feed URL']?.url;
  const url = p['URL']?.url;
  const lang = p['Language']?.select?.name || 'EN';
  const cats = (p['Category Tags']?.multi_select || []).map(o => o.name);
  const desc = (p['Description']?.rich_text || []).map(t => t.plain_text).join('');
  const method = p['Access Method']?.select?.name || 'RSS';
  return { page_id: page.id, name: title, feed_url: feedUrl, url, language: lang,
           category_tags: cats, description: desc, access_method: method };
}).filter(s => s.feed_url || s.access_method === 'Jina' || s.access_method === 'Slack API');

return [{ json: { sources, count: sources.length } }];

const { sources } = $input.first().json;
const LOOKBACK_DAYS = 7;
const MAX_PER_SOURCE = 20;
const cutoff = new Date(Date.now() - LOOKBACK_DAYS * 86400000);

function clean(t) {
  return (t||'').replace(/<[^>]*>/g,'').replace(/&amp;/g,'&').replace(/&lt;/g,'<')
    .replace(/&gt;/g,'>').replace(/&quot;/g,'"').replace(/&#0?39;/g,"'")
    .replace(/&nbsp;/g,' ').replace(/\s+/g,' ').trim();
}

function parseRss(xml) {
  const items = [];
  const rss = /<item[^>]*>([\s\S]*?)<\/item>/gi;
  let m;
  while ((m = rss.exec(xml)) !== null) {
    const x = m[1];
    items.push({
      title: clean((x.match(/<title[^>]*>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/title>/i)||[])[1]||''),
      link: ((x.match(/<link[^>]*>([\s\S]*?)<\/link>/i)||[])[1]||'').trim(),
      date: ((x.match(/<pubDate[^>]*>([\s\S]*?)<\/pubDate>/i)||[])[1]||'').trim(),
      desc: clean((x.match(/<description[^>]*>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/description>/i)||[])[1]||''),
      author: clean((x.match(/<(?:dc:creator|author)[^>]*>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/(?:dc:creator|author)>/i)||[])[1]||''),
    });
  }
  if (!items.length) {
    const atom = /<entry[^>]*>([\s\S]*?)<\/entry>/gi;
    while ((m = atom.exec(xml)) !== null) {
      const x = m[1];
      items.push({
        title: clean((x.match(/<title[^>]*>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/title>/i)||[])[1]||''),
        link: ((x.match(/<link[^>]*href=["']([^"']*)["']/i)||[])[1]||'').trim(),
        date: ((x.match(/<(?:published|updated)[^>]*>([\s\S]*?)<\/(?:published|updated)>/i)||[])[1]||'').trim(),
        desc: clean((x.match(/<(?:summary|content)[^>]*>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/(?:summary|content)>/i)||[])[1]||''),
        author: clean((x.match(/<author[^>]*>[\s\S]*?<name[^>]*>([\s\S]*?)<\/name>/i)||[])[1]||''),
      });
    }
  }
  return items;
}

// Parse articles from Jina reader JSON response (markdown with inline links)
// NOTE: Uses regex for URL parsing because n8n task runner sandbox lacks URL constructor
function parseHost(urlStr) {
  const m = urlStr.match(/^https?:\/\/(?:www\.)?([^\/\?#]+)/i);
  return m ? m[1] : '';
}
function parsePath(urlStr) {
  const m = urlStr.match(/^https?:\/\/[^\/]+(\/[^?#]*)/i);
  return m ? m[1] : '/';
}

function parseJinaPage(resp, sourceUrl) {
  const dateRegex = /(Jan(?:uary)?|Feb(?:ruary)?|Mar(?:ch)?|Apr(?:il)?|May|Jun(?:e)?|Jul(?:y)?|Aug(?:ust)?|Sep(?:tember)?|Oct(?:ober)?|Nov(?:ember)?|Dec(?:ember)?)\s+\d{1,2},?\s+\d{4}/i;
  const data = resp.data || resp;
  const content = data.content || (typeof data === 'string' ? data : '');
  if (!content) return [];

  const sourceHost = parseHost(sourceUrl);
  if (!sourceHost) return [];

  // Extract markdown links: [text](url)
  const linkRegex = /\[([^\]]{10,})\]\((https?:\/\/[^)]+)\)/g;
  const articles = [];
  const seenUrls = new Set();
  let match;

  while ((match = linkRegex.exec(content)) !== null) {
    const text = match[1].trim();
    const url = match[2].trim();

    if (url.includes('#') || text.length < 15) continue;

    // Must be same domain
    const linkHost = parseHost(url);
    if (!linkHost) continue;
    if (!linkHost.includes(sourceHost) && !sourceHost.includes(linkHost)) continue;

    // Must look like an article path (depth > 1)
    const path = parsePath(url);
    if (path.split('/').filter(Boolean).length < 2) continue;

    if (seenUrls.has(url)) continue;
    seenUrls.add(url);

    // Extract date from link text
    const dateMatch = text.match(dateRegex);
    let published = null;
    let title = text;

    if (dateMatch) {
      try {
        const d = new Date(dateMatch[0].replace(',', ''));
        if (!isNaN(d.getTime())) published = d.toISOString();
      } catch(e) {}
      // Remove date from title
      const before = text.substring(0, text.indexOf(dateMatch[0])).trim();
      const after = text.substring(text.indexOf(dateMatch[0]) + dateMatch[0].length).trim();
      title = before.length > after.length ? before : (after || before);
    }

    // Fallback: find date near this URL in content
    if (!published) {
      const urlIdx = content.indexOf(url);
      if (urlIdx >= 0) {
        const start = Math.max(0, urlIdx - 200);
        const nearby = content.substring(start, urlIdx + url.length + 200);
        const contentDate = nearby.match(dateRegex);
        if (contentDate) {
          try {
            const d = new Date(contentDate[0].replace(',', ''));
            if (!isNaN(d.getTime())) published = d.toISOString();
          } catch(e) {}
        }
      }
    }

    // Clean title
    title = title.replace(/^(Research|Product|Company|Engineering|Policy|Science|Announcements|Solutions|Computer Vision|ML applications|Open Source|Natural language processing|Speech & Audio|Hardware|Featured|FEATURED|Latest News)\s*/i, '').trim();
    title = title.replace(/\s*(Mistral AI|By\s+.{0,50}$)/i, '').trim();
    title = title.replace(/^#+\s*/, '').trim();

    if (!title || title.length < 10) continue;

    // Filter by lookback (if we have a date)
    if (published) {
      const pubDate = new Date(published);
      if (!isNaN(pubDate.getTime()) && pubDate < cutoff) continue;
    }

    articles.push({ title: title.substring(0, 200), url, published, summary: text.substring(0, 500) });
  }
  return articles;
}


const allItems = [];
const errors = [];
const processed = [];

// ═══ Process RSS sources ═══
const rssSources = sources.filter(s => s.access_method === 'RSS' && s.feed_url);
for (const src of rssSources) {
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET', url: src.feed_url,
      headers: { 'Accept': 'application/rss+xml, application/atom+xml, text/xml',
                 'User-Agent': 'T0-SourceIngestion/1.0' },
      returnFullResponse: true, ignoreHttpStatusErrors: true, timeout: 15000,
    });
    const xml = typeof resp.body === 'string' ? resp.body : '';
    if (!xml || resp.statusCode >= 400) {
      errors.push({ source: src.name, error: 'HTTP ' + resp.statusCode });
      continue;
    }
    const items = parseRss(xml);
    const recent = items.filter(it => {
      if (!it.date) return true;
      const d = new Date(it.date);
      return !isNaN(d.getTime()) && d >= cutoff;
    }).slice(0, MAX_PER_SOURCE);

    for (const it of recent) {
      allItems.push({
        title: it.title, url: it.link,
        published: it.date || new Date().toISOString(),
        summary: (it.desc || '').substring(0, 500),
        full_text: it.desc || '',
        source_name: src.name, source_page_id: src.page_id,
        source_category_tags: src.category_tags,
        origin: 'rss-ingestion',
        origin_description: src.name + ' RSS',
        author: it.author, language: src.language,
      });
    }
    processed.push({ page_id: src.page_id, name: src.name, count: recent.length });
  } catch (e) {
    errors.push({ source: src.name, error: e.message || String(e) });
  }
}

// ═══ Process Jina sources ═══
const jinaSources = sources.filter(s => s.access_method === 'Jina' && s.url);
for (const src of jinaSources) {
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://r.jina.ai/' + src.url,
      headers: {
        'Accept': 'application/json',
        'X-With-Links': 'true',
        'User-Agent': 'T0-SourceIngestion/1.0',
      },
      timeout: 30000,
    });



    const articles = parseJinaPage(resp, src.url);
    for (const art of articles.slice(0, MAX_PER_SOURCE)) {
      allItems.push({
        title: art.title, url: art.url,
        published: art.published || new Date().toISOString(),
        summary: art.summary,
        full_text: '',
        source_name: src.name, source_page_id: src.page_id,
        source_category_tags: src.category_tags,
        origin: 'jina-ingestion',
        origin_description: src.name + ' (Jina)',
        author: '', language: src.language,
      });
    }
    processed.push({ page_id: src.page_id, name: src.name, count: Math.min(articles.length, MAX_PER_SOURCE) });
  } catch (e) {
    errors.push({ source: src.name, error: e.message || String(e) });
  }
}


return [{ json: {
  items: allItems, item_count: allItems.length,
  sources_processed: processed, source_count: processed.length,
  errors, error_count: errors.length,
}}];

// Dedup against existing Notes
const rssData = $('Fetch & Parse RSS').first().json;
const notesResp = $('Fetch Recent Notes').first().json;
const items = rssData.items || [];
const existingNotes = notesResp.results || [];

// Build URL set from existing notes
const existingUrls = new Set();
const existingTitles = [];
for (const n of existingNotes) {
  const url = n.properties?.URL?.url;
  if (url) existingUrls.add(url.toLowerCase().replace(/\/+$/, ''));
  const t = (n.properties?.Name?.title || []).map(x => x.plain_text).join('');
  if (t) existingTitles.push(t.toLowerCase().replace(/[^a-z0-9\s]/g, '').substring(0, 80));
}

const unique = [];
const seen = new Set();
let dupUrl = 0, dupTitle = 0;

for (const item of items) {
  const normUrl = (item.url || '').toLowerCase().replace(/\/+$/, '');
  if (normUrl && (existingUrls.has(normUrl) || seen.has(normUrl))) { dupUrl++; continue; }

  const normTitle = (item.title || '').toLowerCase().replace(/[^a-z0-9\s]/g, '').substring(0, 80);
  if (normTitle.length > 10) {
    const isDup = existingTitles.some(ex => {
      if (ex.length < 10) return false;
      let matches = 0;
      const len = Math.min(normTitle.length, ex.length);
      for (let i = 0; i < len; i++) if (normTitle[i] === ex[i]) matches++;
      return (matches / Math.max(normTitle.length, ex.length)) > 0.85;
    });
    if (isDup) { dupTitle++; continue; }
  }

  seen.add(normUrl);
  unique.push(item);
}

return [{ json: {
  items: unique, item_count: unique.length,
  dedup: { url: dupUrl, title: dupTitle, total_removed: dupUrl + dupTitle },
  sources_processed: rssData.sources_processed,
  errors: rssData.errors,
}}];

const THRESHOLD = 3;
const mergeData = $input.first().json;
const items = mergeData.items || [];
const results = mergeData.triage_results || [];

const passing = [];
for (let i = 0; i < items.length; i++) {
  const t = results.find(r => r.index === i) || {};
  const score = t.relevance_score || 0;
  if (score >= THRESHOLD) {
    passing.push({
      ...items[i], relevance_score: score,
      triage_category_tags: t.category_tags || items[i].source_category_tags || [],
      triage_ai_tags: t.ai_tags || [],
      triage_summary: t.summary || items[i].summary,
    });
  }
}

return [{ json: {
  items: passing, item_count: passing.length,
  filtered: items.length - passing.length,
  total_scored: results.length,
  total_items: items.length,
  sources_processed: mergeData.sources_processed,
}}];

// Compute 30-day lookback date for dedup query
const cutoff = new Date(Date.now() - 30 * 86400000).toISOString();
const queryBody = JSON.stringify({
  filter: {
    and: [
      { property: "URL", url: { is_not_empty: true } },
      { timestamp: "created_time", created_time: { after: cutoff } }
    ]
  },
  page_size: 100
});
return [{ json: { queryBody, cutoff } }];

// Split items into batches of 25 for reliable triage scoring
const data = $input.first().json;
const items = data.items || [];

if (items.length === 0) {
  return [{ json: {
    requestBody: JSON.stringify({
      model: 'anthropic/claude-3.5-haiku',
      messages: [{ role: 'user', content: 'No items. Return: {"results": []}' }],
      max_tokens: 50,
    }),
    batchItems: [],
    sources_processed: data.sources_processed || [],
  }}];
}

const BATCH_SIZE = 25;
const output = [];

for (let b = 0; b < Math.ceil(items.length / BATCH_SIZE); b++) {
  const start = b * BATCH_SIZE;
  const batch = items.slice(start, start + BATCH_SIZE);

  const itemList = batch.map((it, i) =>
    `[${start + i}] ${it.title} (${it.source_name}): ${(it.summary || '').substring(0, 200)}`
  ).join('\n');

  const systemPrompt = `You are a content strategist for T-0, a German AI transformation agency.

Score each item for relevance to T-0 (1-5):
5 = Directly relevant (AI agents, MCP, enterprise AI, German market)
4 = Clearly relevant, T-0 audience would value this
3 = Moderately relevant, useful context
2 = Tangentially related
1 = Not relevant

T-0 focus: AI agents/automation, MCP/tool-use, enterprise AI adoption, German/DACH market, developer tools, infrastructure.

Category Tags (pick 1-3): AI Models, Agents & Automation, Context Engineering, Dev Tools, Infrastructure, Security, Industry Moves, Regulation, Funding, Competitors, Strategy, Work & Society, German Market, MCP

Respond with ONLY a JSON object. No markdown, no code blocks, no other text.
{"results": [{"index": 0, "relevance_score": 4, "category_tags": ["AI Models"], "ai_tags": ["Claude"], "summary": "2-3 sentence summary."}, ...]}

You MUST score every single item. Score ALL ${batch.length} items from index ${start} to ${start + batch.length - 1}.`;

  const requestBody = JSON.stringify({
    model: 'anthropic/claude-3.5-haiku',
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: `Score these ${batch.length} items:\n\n${itemList}` },
    ],
    temperature: 0.1,
    max_tokens: 4000,
  });

  output.push({ json: {
    requestBody,
    batchItems: batch,
    batch_index: b,
    batch_start: start,
    sources_processed: b === 0 ? (data.sources_processed || []) : [],
  }});
}

return output;

const data = $input.first().json;
const items = data.items || [];
if (items.length === 0) return [];

const NOTES_DB = '2afc0fdf-942d-819a-b859-e69dcc48d67d';
const output = [];

for (const item of items) {
  const props = {
    'Name': { title: [{ text: { content: (item.title || 'Untitled').substring(0, 200) } }] },
    'Status': { status: { name: 'To Be Processed' } },
    'Origin': { multi_select: [{ name: 'rss-ingestion' }] },
    'Origin Description': { rich_text: [{ text: { content: (item.origin_description || '').substring(0, 200) } }] },
    'Summary': { rich_text: [{ text: { content: (item.triage_summary || item.summary || '').substring(0, 2000) } }] },
    'AI-Tags': { multi_select: (item.triage_ai_tags || []).slice(0, 5).map(t => ({ name: t })) },
  };

  if (item.url) props['URL'] = { url: item.url };
  if (item.published) {
    try {
      const dt = new Date(item.published);
      if (!isNaN(dt.getTime())) props['Time'] = { date: { start: dt.toISOString().split('T')[0] } };
    } catch(e) {}
  }
  if (item.full_text) {
    props['Description'] = { rich_text: [{ text: { content: item.full_text.substring(0, 2000) } }] };
  }
  const firstCat = (item.triage_category_tags || [])[0];
  if (firstCat) props['Category Tags'] = { select: { name: firstCat } };
  if (item.source_page_id) props['Source'] = { relation: [{ id: item.source_page_id }] };

  output.push({ json: {
    requestBody: JSON.stringify({ parent: { database_id: NOTES_DB }, properties: props }),
    title: item.title,
    source_name: item.source_name,
  }});
}
return output;

const data = $('Parse Triage & Gate').first().json;
const sourcesProcessed = data.sources_processed || [];
const now = new Date().toISOString();
const seen = new Set();
const output = [];

for (const src of sourcesProcessed) {
  if (seen.has(src.page_id)) continue;
  seen.add(src.page_id);
  output.push({ json: {
    url: 'https://api.notion.com/v1/pages/' + src.page_id,
    requestBody: JSON.stringify({
      properties: { 'Last Checked': { date: { start: now } } }
    }),
    source_name: src.name,
  }});
}

if (output.length === 0) return [];
return output;

// Collect all batch triage responses and merge results
const triageResponses = $('AI Triage').all();
const batchOutputs = $('Prepare Triage').all();

// Collect all items from all batches
const allItems = [];
for (const batch of batchOutputs) {
  allItems.push(...(batch.json.batchItems || []));
}

// Collect sources_processed from first batch
const sourcesProcessed = batchOutputs[0]?.json.sources_processed || [];

// Parse all triage results
const allResults = [];
let parseErrors = 0;
for (const resp of triageResponses) {
  try {
    const content = resp.json.choices?.[0]?.message?.content || '{}';
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      const parsed = JSON.parse(jsonMatch[0]);
      allResults.push(...(parsed.results || []));
    }
  } catch (e) {
    parseErrors++;
  }
}

return [{ json: {
  items: allItems,
  triage_results: allResults,
  sources_processed: sourcesProcessed,
  batches_processed: triageResponses.length,
  items_scored: allResults.length,
  parse_errors: parseErrors,
}}];

const historyResp = $input.first().json;
if (!historyResp.ok) {
  return [{ json: { threads: [], error: historyResp.error || 'Slack API error' } }];
}

const messages = historyResp.messages || [];
// Qualifying threads: 2+ replies from 2+ people
const threadMessages = messages.filter(m => (m.reply_count || 0) >= 2 && (m.reply_users_count || 0) >= 2);

// Also capture standalone link shares
const linkMessages = messages.filter(m =>
  (m.reply_count || 0) < 2 &&
  m.text && m.text.includes('<http')
);

// Output one item per thread that needs replies fetched
const threadItems = threadMessages.map(m => ({
  json: { thread_ts: m.ts, parent_text: m.text || '', reply_count: m.reply_count, is_thread: true }
}));

// Also output link messages (don't need reply fetching)
const linkItems = linkMessages.map(m => ({
  json: { thread_ts: m.ts, parent_text: m.text || '', reply_count: 0, is_thread: false }
}));

// Return all items (threads first, then links)
const all = [...threadItems, ...linkItems];
if (!all.length) {
  return [{ json: { thread_ts: '', parent_text: '', reply_count: 0, is_thread: false, no_items: true } }];
}
return all;

// Collect all identify outputs and their corresponding replies
const identifyItems = $('Identify Slack Threads').all();
const replyItems = $('Fetch Slack Replies').all();

// Get Slack source info from Extract Sources
const sources = $('Extract Sources').first().json.sources || [];
const slackSource = sources.find(s => s.access_method === 'Slack API');
if (!slackSource) {
  return [{ json: { slackItems: [], count: 0 } }];
}

const SLACK_CHANNEL_ID = 'C07RWPA1Z0B';
const MAX_PER_SOURCE = 20;
const items = [];

for (let i = 0; i < identifyItems.length; i++) {
  const ident = identifyItems[i].json;
  if (ident.no_items) continue;

  let threadText = ident.parent_text || '';
  let allLinks = [];

  if (ident.is_thread && i < replyItems.length) {
    // Use reply data if available
    const replyResp = replyItems[i]?.json;
    if (replyResp?.ok) {
      const replies = replyResp.messages || [];
      threadText = replies.map(r => r.text || '').join('\n\n');
      for (const r of replies) {
        const linkMatches = (r.text || '').match(/<(https?:[^>|]+)(?:\|[^>]*)?>/g) || [];
        for (const lm of linkMatches) {
          const url = lm.match(/<(https?:[^>|]+)/)?.[1];
          if (url) allLinks.push(url);
        }
      }
    }
  }

  // Extract links from parent text if no reply links
  if (!allLinks.length) {
    const linkMatches = (ident.parent_text || '').match(/<(https?:[^>|]+)(?:\|[^>]*)?>/g) || [];
    for (const lm of linkMatches) {
      const url = lm.match(/<(https?:[^>|]+)/)?.[1];
      if (url) allLinks.push(url);
    }
  }

  const cleanText = threadText.replace(/<[^>]+>/g, '').replace(/:[a-z_]+:/g, '').trim();
  let title = cleanText.split('\n')[0].trim().substring(0, 200);
  if (!title || title.length < 5) title = 'Slack thread ' + new Date(parseFloat(ident.thread_ts) * 1000).toISOString().split('T')[0];

  const threadUrl = allLinks[0] || `https://tminusnull.slack.com/archives/${SLACK_CHANNEL_ID}/p${ident.thread_ts.replace('.', '')}`;
  const published = new Date(parseFloat(ident.thread_ts) * 1000).toISOString();
  const originDesc = ident.is_thread ? slackSource.name + ' (Slack thread)' : slackSource.name + ' (Slack link)';

  items.push({
    title,
    url: threadUrl,
    published,
    summary: cleanText.substring(0, 500),
    full_text: cleanText.substring(0, 2000),
    source_name: slackSource.name,
    source_page_id: slackSource.page_id,
    source_category_tags: slackSource.category_tags,
    origin: 'slack-capture',
    origin_description: originDesc,
    author: '',
    language: slackSource.language,
  });
}

return [{ json: { slackItems: items.slice(0, MAX_PER_SOURCE), count: Math.min(items.length, MAX_PER_SOURCE), source: slackSource } }];

// Read from both branches
// Input 1: Fetch & Parse RSS (RSS + Jina items)
// Input 2: Normalize Slack Items (Slack items)
const inputs = $input.all();

let rssData = null;
let slackData = null;

// Find RSS and Slack data in inputs
for (const item of inputs) {
  const j = item.json;
  if (j.items && j.item_count !== undefined) {
    rssData = j;
  }
  if (j.slackItems !== undefined) {
    slackData = j;
  }
}

let allItems = [];
let allProcessed = [];
let allErrors = [];

if (rssData) {
  allItems.push(...(rssData.items || []));
  allProcessed.push(...(rssData.sources_processed || []));
  allErrors.push(...(rssData.errors || []));
}

if (slackData && slackData.slackItems) {
  allItems.push(...slackData.slackItems);
  if (slackData.source) {
    allProcessed.push({ page_id: slackData.source.page_id, name: slackData.source.name, count: slackData.count });
  }
}

return [{ json: {
