    allProcessed.push({ page_id: slackData.source.page_id, name: slackData.source.name, count: slackData.count });
  }
}

return [{ json: {
  items: allItems,
  item_count: allItems.length,
  sources_processed: allProcessed,
  source_count: allProcessed.length,
  errors: allErrors,
  error_count: allErrors.length,
} }];
